#[test]
fn role_target_bands() {
    let (min, max) = HomeCinemaRole::Lfe.default_target_band_hz();
    assert_eq!((min, max), (20.0, 160.0));

    let (min, max) = HomeCinemaRole::Subwoofer.default_target_band_hz();
    assert_eq!((min, max), (20.0, 160.0));

    let (min, max) = HomeCinemaRole::Center.default_target_band_hz();
    assert_eq!((min, max), (80.0, 16_000.0));

    let (min, max) = HomeCinemaRole::SideSurroundLeft.default_target_band_hz();
    assert_eq!((min, max), (80.0, 12_000.0));

    let (min, max) = HomeCinemaRole::TopFrontLeft.default_target_band_hz();
    assert_eq!((min, max), (120.0, 10_000.0));

    let (min, max) = HomeCinemaRole::Unknown.default_target_band_hz();
    assert_eq!((min, max), (20.0, 20_000.0));
}

