#[test]
fn role_for_channel_role_score_band_clamps_to_config() {
    use crate::roomeq::types::{OptimizerConfig, RoomConfig, SpeakerConfig};
    use std::collections::HashMap;

    let mut speakers = HashMap::new();
    speakers.insert(
        "left".to_string(),
        SpeakerConfig::Single(crate::MeasurementSource::InMemory(crate::Curve {
            freq: ndarray::Array1::from_vec(vec![20.0, 100.0, 1000.0]),
            spl: ndarray::Array1::from_vec(vec![80.0, 80.0, 80.0]),
            phase: None,
            ..Default::default()
        })),
    );

    let config = RoomConfig {
        version: crate::roomeq::types::default_config_version(),
        system: None,
        speakers,
        crossovers: None,
        target_curve: None,
        optimizer: OptimizerConfig {
            min_freq: 50.0,
            max_freq: 10_000.0,
            ..Default::default()
        },
        recording_config: None,
        ctc: None,
        cea2034_cache: None,
    };

    let (min, max) = role_score_band(&config, "L");
    assert_eq!(min, 50.0); // clamped to config.min_freq
    assert_eq!(max, 10_000.0); // clamped to config.max_freq
}
